/**
 * Zip two arrays into tuple pairs.
 * @param {unknown[]} left
 * @param {unknown[]} right
 * @returns {unknown[][]}
 * @throws {TypeError} When arguments are not arrays
 */
export function zipArrays(left, right) {
  if (!Array.isArray(left) || !Array.isArray(right)) {
    throw new TypeError('left and right must be arrays');
  }
  const length = Math.min(left.length, right.length);
  const pairs = [];
  for (let index = 0; index < length; index += 1) {
    pairs.push([left[index], right[index]]);
  }
  return pairs;
}
